(function(){var logArea=document.getElementById("log")||document.body.appendChild(document.createElement("pre"));logArea.id="log";if(window._debugMessages&&window._debugMessages.length>0){for(var i=0;i<window._debugMessages.length;i++){logArea.textContent+=window._debugMessages[i]+"\n"}window._debugMessages=[]}console.log=function(){var msg=Array.prototype.slice.call(arguments).join(" ");logArea.textContent+="console.log: "+msg+"\n"};console.info=function(){var msg=Array.prototype.slice.call(arguments).join(" ");logArea.textContent+="console.info: "+msg+"\n"};console.error=function(){var msg=Array.prototype.slice.call(arguments).join(" ");logArea.textContent+="console.error: "+msg+"\n"};console.warn=function(){var msg=Array.prototype.slice.call(arguments).join(" ");logArea.textContent+="console.warn: "+msg+"\n"};window.onerror=function(msg,url,lineNo,columnNo,error){logArea.textContent+="Error: "+msg+" at "+url+":"+lineNo+":"+columnNo+"\n";if(error){logArea.textContent+="Stack trace: "+error.stack+"\n"}return false}})();